def test_get_route_wrap_correct_fields():
    """Test to check correct route data structure"""

    # Provider with mocked get_route method
    test_tt_provider = Provider.from_properties(
        name="TT",
        endpoint="https://api.tomtom.com/routing/1/calculateRoute/",
    )
    test_tt_provider.get_route = mocked_get_route

    test_row = Row(
        org="fake_org",
        origin=[-18.00422, 27.75411],
        destination=[-18.01009, 27.75498],
        route_id="fake_id",
    )

    get_route_wrap_results = get_route_wrap(
        provider=test_tt_provider,
        row=test_row,
    )

    # Valid route
    valid = get_route_wrap_results[0]
    assert valid

    # All fields
    assert len(get_route_wrap_results) == 8

    # Not modified
    assert get_route_wrap_results[1] == "fake_org"
    assert get_route_wrap_results[2] == [-18.00422, 27.75411]
    assert get_route_wrap_results[3] == [-18.01009, 27.75498]
    assert get_route_wrap_results[4] == "fake_id"

    # Correct values
    route_geometry = get_route_wrap_results[5]
    assert len(route_geometry) == 321

    route_distance = get_route_wrap_results[6]
    assert isinstance(route_distance, float)
    assert pytest.approx(route_distance, 9468.672508876441)

    route_time = get_route_wrap_results[7]
    assert isinstance(route_time, int)
    assert route_time == 120


def test_get_feats_ids():
    """Test correct get_feats_ids"""
    get_feats_ids_results = get_feats_ids(route=FEAT_IDS_ROUTE, distance=112078.0)
    assert isinstance(get_feats_ids_results, list)
    for feature in get_feats_ids_results:
        assert isinstance(feature, dict)

        assert "properties" in feature.keys()
        assert "id" in feature["properties"].keys()
        feat_id = feature["properties"]["id"]
        assert isinstance(feat_id, str)

        assert "geometry" in feature.keys()
        assert "coordinates" in feature["geometry"].keys()
        assert isinstance(feature["geometry"]["coordinates"], list)

        assert "traveledDistance" in feature["properties"].keys()
        assert "value" in feature["properties"]["traveledDistance"].keys()
        travel_distance = feature["properties"]["traveledDistance"]["value"]
        assert isinstance(travel_distance, int) or isinstance(travel_distance, float)


def test_geom_is_mdr(requests_mock):
    """Test is_mdr function"""
    geom = "LINESTRING (-18.0099204183 27.7546674013, -18.010006249 27.7549906075)"
    requests_mock.post(
        "http://driven-km-lb-e047cd72a7da7f10.elb.eu-west-1.amazonaws.com:8080"
        "/driven-kilometers-scope-service/in-scope",
        content=b"true",
    )
    assert is_mdr(geom)

    requests_mock.post(
        "http://driven-km-lb-e047cd72a7da7f10.elb.eu-west-1.amazonaws.com:8080"
        "/driven-kilometers-scope-service/in-scope",
        content=b"false",
    )
    assert not is_mdr(geom)


def test_wrap_get_feats_ids(mocker):
    """Test correct wrap_get_feats_ids"""
    mocker.patch("tbt.pipelines.sampling_hdr.nodes.get_feats_ids", mocked_get_feats_ids)

    test_row = Row(
        route_id="fake_route_id",
        origin=[-18.00426, 27.75414],
        destination=[-18.00426, 27.75414],
        route=[[-18.00426, 27.75414], [-18.00426, 27.75414]],
        distance=0,
    )
